-- Add unified sentence growth data for verb paths.
-- growth_json combines sentence animation steps with node/link structure for tree visualization.

ALTER TABLE verb_paths ADD COLUMN growth_json TEXT NOT NULL DEFAULT '{"nodes":[],"links":[],"steps":[]}';

UPDATE verb_paths SET growth_json = '{"nodes":[{"id":"the-team","text":"the team","kind":"core","group":"core"},{"id":"adds","text":"adds","kind":"action","group":"action"},{"id":"a-flag","text":"a flag","kind":"core","group":"core"},{"id":"small","text":"small","kind":"modifier","group":"modifier"},{"id":"to-the-config","text":"to the config","kind":"modifier","group":"modifier"},{"id":"before-the-rollout","text":"Before the rollout","kind":"modifier","group":"modifier"},{"id":"turn-off-quickly","text":"so the feature can be turned off quickly","kind":"modifier","group":"modifier"}],"links":[{"id":"adds->the-team","from":"adds","to":"the-team","kind":"core","label":"谁在添加"},{"id":"adds->a-flag","from":"adds","to":"a-flag","kind":"core","label":"添加什么"},{"id":"small->a-flag","from":"small","to":"a-flag","kind":"modifier","label":"说明开关大小"},{"id":"to-the-config->adds","from":"to-the-config","to":"adds","kind":"modifier","label":"说明添加到哪里"},{"id":"before-the-rollout->adds","from":"before-the-rollout","to":"adds","kind":"modifier","label":"说明什么时候添加"},{"id":"turn-off-quickly->adds","from":"turn-off-quickly","to":"adds","kind":"modifier","label":"说明为什么添加"}],"steps":[{"step_no":1,"label":"主干","sentence_en":"The team adds a flag.","sentence_zh":"团队添加一个开关。","show_nodes":["the-team","adds","a-flag"],"show_links":["adds->the-team","adds->a-flag"],"focus_node":"adds","note_zh":"先看最核心的动作：团队添加一个开关。"},{"step_no":2,"label":"加一点对象细节","sentence_en":"The team adds a small flag to the config.","sentence_zh":"团队在配置里添加一个小开关。","show_nodes":["small","to-the-config"],"show_links":["small->a-flag","to-the-config->adds"],"focus_node":"to-the-config","note_zh":"这一步让“添加什么、加到哪里”更具体。"},{"step_no":3,"label":"加一点时间","sentence_en":"Before the rollout, the team adds a small flag to the config.","sentence_zh":"上线前，团队在配置里添加一个小开关。","show_nodes":["before-the-rollout"],"show_links":["before-the-rollout->adds"],"focus_node":"before-the-rollout","note_zh":"这一步说明动作发生在上线之前。"},{"step_no":4,"label":"加一点目的","senten