UPDATE verb_paths SET growth_json = '{"nodes":[{"id":"the-script","text":"the script","kind":"core","group":"core"},{"id":"adjusts","text":"adjusts","kind":"action","group":"action"},{"id":"the-timeout","text":"the timeout","kind":"core","group":"core"},{"id":"slightly","text":"slightly","kind":"modifier","group":"modifier"},{"id":"when-requests-slow-down","text":"When requests slow down","kind":"modifier","group":"modifier"},{"id":"keep-the-job-stable","text":"to keep the job stable","kind":"modifier","group":"modifier"}],"links":[{"id":"adjusts->the-script","from":"adjusts","to":"the-script","kind":"core","label":"谁在调整"},{"id":"adjusts->the-timeout","from":"adjusts","to":"the-timeout","kind":"core","label":"调整什么"},{"id":"slightly->adjusts","from":"slightly","to":"adjusts","kind":"modifier","label":"说明调整幅度"},{"id":"when-requests-slow-down->adjusts","from":"when-requests-slow-down","to":"adjusts","kind":"modifier","label":"说明什么时候调整"},{"id":"keep-the-job-stable->adjusts","from":"keep-the-job-stable","to":"adjusts","kind":"modifier","label":"说明为什么调整"}],"steps":[{"step_no":1,"label":"主干","sentence_en":"The script adjusts the timeout.","sentence_zh":"脚本调整超时时间。","show_nodes":["the-script","adjusts","the-timeout"],"show_links":["adjusts->the-script","adjusts->the-timeout"],"focus_node":"adjusts","note_zh":"先看核心：脚本在调整超时时间。"},{"step_no":2,"label":"加一点程度","sentence_en":"The script adjusts the timeout slightly.","sentence_zh":"脚本稍微调整超时时间。","show_nodes":["slightly"],"show_links":["slightly->adjusts"],"focus_node":"slightly","note_zh":"这一步说明调整幅度不大。"},{"step_no":3,"label":"加一点条件","sentence_en":"When requests slow down, the script adjusts the timeout slightly.","sentence_zh":"当请求变慢时，脚本会稍微调整超时时间。","show_nodes":["when-requests-slow-down"],"show_links":["when-requests-slow-down->adjusts"],"focus_node":"when-requests-slow-down","note_zh":"这一步说明什么情况下会调整。"},{"step_no":4,"label":"加一点目的","sentence_en":"When requests slow down, the script adjusts the timeout slightly to keep the job stable.","sentence_zh":"当请求变慢时，脚本会稍微调整超时时间，让任务保持稳定。","show_nodes":["keep-the-job-stable"],"show_links":["keep-the-job-stable->adjusts"],"focus_node":"keep-the-job-stable","note_zh":"这一步说明调整是为了让任务稳定运行。"}]}' WHERE id = 'adjust-timeout';
